var building = new Building(1, "Engineering Building", "Blue", 15.5, 30.0, 20.0, 100.0, 200.0, 0.0);
Assert.That(building.InternalID, Is.EqualTo(1));
Assert.That(building.Name, Is.EqualTo("Engineering Building"));
Assert.That(building.Color, Is.EqualTo("Blue"));
Assert.That(building.Height, Is.EqualTo(15.5));

// Verify that Building constructor throws ArgumentException when Name is null
Assert.Throws<ArgumentException>(() =>
{
    var building = new Building(internalID: 1, name: null, color: "Blue", height: 15.5, length: 30.0, width: 20.0, x: 100.0, y: 200.0, z: 0.0);
});

// Verify that Building constructor throws ArgumentException when Name is empty
Assert.Throws<ArgumentException>(() =>
{
    var building = new Building(1, "", "Blue", 15.5, 30.0, 20.0, 100.0, 200.0, 0.0);
});

// Verify that Building constructor throws ArgumentException when Color is null
Assert.Throws<ArgumentException>(() =>
{
    var building = new Building(1, "Engineering Building", null, 15.5, 30.0, 20.0, 100.0, 200.0, 0.0);
});

// Verify that Building constructor throws ArgumentException when Height is negative
Assert.Throws<ArgumentException>(() =>
{
    var building = new Building(1, "Engineering Building", "Blue", -15.5, 30.0, 20.0, 100.0, 200.0, 0.0);
});

// Verify that Building constructor throws ArgumentException when Height is zero
Assert.Throws<ArgumentException>(() =>
{
    var building = new Building(1, "Engineering Building", "Blue", 0.0, 30.0, 20.0, 100.0, 200.0, 0.0);
});

// Verify that Building constructor throws ArgumentException when Length is negative
Assert.Throws<ArgumentException>(() =>
{
    var building = new Building(1, "Engineering Building", "Blue", 15.5, -30.0, 20.0, 100.0, 200.0, 0.0);
});

// Verify that Building constructor throws ArgumentException when Width is negative
Assert.Throws<ArgumentException>(() =>
{
    var building = new Building(1, "Engineering Building", "Blue", 15.5, 30.0, -20.0, 100.0, 200.0, 0.0);
});

// Verify that Building constructor throws ArgumentException when X coordinate is negative
Assert.Throws<ArgumentException>(() =>
{
    var building = new Building(1, "Engineering Building", "Blue", 15.5, 30.0, 20.0, -100.0, 200.0, 0.0);
});

// Verify that Building constructor throws ArgumentException when Y coordinate is negative
Assert.Throws<ArgumentException>(() =>
{
    var building = new Building(1, "Engineering Building", "Blue", 15.5, 30.0, 20.0, 100.0, -200.0, 0.0);
});

// Verify that Building constructor throws ArgumentException when Z coordinate is negative
Assert.Throws<ArgumentException>(() =>
{
    var building = new Building(1, "Engineering Building", "Blue", 15.5, 30.0, 20.0, 100.0, 200.0, -5.0);
});

// Mock repository returns null (no duplicate), then returns true on Add
_mockRepository.Setup(r => r.GetByNameAsync("Engineering Building")).ReturnsAsync((Building)null);
_mockRepository.Setup(r => r.AddAsync(It.IsAny<Building>())).ReturnsAsync(true);

var result = await _service.AddBuildingAsync("Engineering Building", "Blue", 15.5, 30.0, 20.0, 100.0, 200.0, 0.0);

Assert.That(result, Is.True);
_mockRepository.Verify(r => r.GetByNameAsync("Engineering Building"), Times.Once);
_mockRepository.Verify(r => r.AddAsync(It.IsAny<Building>()), Times.Once);

// Mock repository returns existing building with same name
var existingBuilding = new Building(1, "Engineering Building", "Red", 10.0, 20.0, 15.0, 50.0, 60.0, 0.0);
_mockRepository.Setup(r => r.GetByNameAsync("Engineering Building")).ReturnsAsync(existingBuilding);

Assert.ThrowsAsync<InvalidOperationException>(async () =>
{
    await _service.AddBuildingAsync("Engineering Building", "Blue", 15.5, 30.0, 20.0, 100.0, 200.0, 0.0);
});

_mockRepository.Verify(r => r.GetByNameAsync("Engineering Building"), Times.Once);
_mockRepository.Verify(r => r.AddAsync(It.IsAny<Building>()), Times.Never);

// Service validates null name before calling repository
Assert.ThrowsAsync<ArgumentException>(async () =>
{
    await _service.AddBuildingAsync(null, "Blue", 15.5, 30.0, 20.0, 100.0, 200.0, 0.0);
});

_mockRepository.Verify(r => r.GetByNameAsync(It.IsAny<string>()), Times.Never);
_mockRepository.Verify(r => r.AddAsync(It.IsAny<Building>()), Times.Never);

// Service validates null color before calling repository
Assert.ThrowsAsync<ArgumentException>(async () =>
{
    await _service.AddBuildingAsync("Engineering Building", null, 15.5, 30.0, 20.0, 100.0, 200.0, 0.0);
});

_mockRepository.Verify(r => r.AddAsync(It.IsAny<Building>()), Times.Never);

// Arrange: create building and add to repository
var building = new Building(1, "Engineering Building", "Blue", 15.5, 30.0, 20.0, 100.0, 200.0, 0.0);

// Act
var result = await _repository.AddAsync(building);

// Assert
Assert.That(result, Is.True);
var savedBuilding = await _repository.GetByNameAsync("Engineering Building");
Assert.That(savedBuilding, Is.Not.Null);
Assert.That(savedBuilding.Name, Is.EqualTo("Engineering Building"));

// Query for non-existent building
var result = await _repository.GetByNameAsync("NonExistentBuilding");

Assert.That(result, Is.Null);

// Add a building first
var building = new Building(1, "Science Building", "Green", 20.0, 40.0, 30.0, 150.0, 250.0, 0.0);
await _repository.AddAsync(building);

// Query by name
var result = await _repository.GetByNameAsync("Science Building");

Assert.That(result, Is.Not.Null);
Assert.That(result.Name, Is.EqualTo("Science Building"));
Assert.That(result.Color, Is.EqualTo("Green"));

// Mock service returns true
var request = new AddBuildingRequest
{
    Name = "Engineering Building",
    Color = "Blue",
    Height = 15.5,
    Length = 30.0,
    Width = 20.0,
    X = 100.0,
    Y = 200.0,
    Z = 0.0
};

_mockService.Setup(s => s.AddBuildingAsync("Engineering Building", "Blue", 15.5, 30.0, 20.0, 100.0, 200.0, 0.0))
    .ReturnsAsync(true);

var result = await _handler.HandleAsync(request);

Assert.That(result.Success, Is.True);
_mockService.Verify(s => s.AddBuildingAsync("Engineering Building", "Blue", 15.5, 30.0, 20.0, 100.0, 200.0, 0.0), Times.Once);

// Mock service throws InvalidOperationException for duplicate
var request = new AddBuildingRequest
{
    Name = "Engineering Building",
    Color = "Blue",
    Height = 15.5,
    Length = 30.0,
    Width = 20.0,
    X = 100.0,
    Y = 200.0,
    Z = 0.0
};

_mockService.Setup(s => s.AddBuildingAsync(It.IsAny<string>(), It.IsAny<string>(), It.IsAny<double>(), It.IsAny<double>(), It.IsAny<double>(), It.IsAny<double>(), It.IsAny<double>(), It.IsAny<double>()))
    .ThrowsAsync(new InvalidOperationException("Building with this name already exists"));

var result = await _handler.HandleAsync(request);

Assert.That(result.Success, Is.False);
Assert.That(result.ErrorMessage, Does.Contain("already exists"));

